 1	import React, { FC, ReactNode, useEffect, useState } from 'react';
 2	import classNames from 'classnames';
 3	
 4	import { ExpandableSection } from '@patternfly/react-core';
 5	
 6	import './ExpandSection.scss';
 7	
 8	type ExpandSectionProps = {
 9	  className?: string;
10	  dataTestID?: string;
11	  isDisabled?: boolean;
12	  isIndented?: boolean;
13	  toggleContent?: ReactNode;
14	  toggleText?: string;
15	};
16	
17	const ExpandSection: FC<ExpandSectionProps> = ({
18	  children,
19	  className,
20	  dataTestID,
21	  isDisabled = false,
22	  isIndented = true,
23	  toggleContent = null,
24	  toggleText = '',
25	}) => {
26	  const [isExpanded, setIsExpanded] = useState(false);
27	
28	  useEffect(() => {
29	    if (isDisabled) setIsExpanded(false);
30	  }, [isDisabled, setIsExpanded]);
31	
32	  const handleToggle = (expanded: boolean) => (isDisabled ? null : setIsExpanded(expanded));
33	
34	  return (
35	    <ExpandableSection
36	      className={classNames(className, { 'expand-section__disabled': isDisabled }, 'ExpandSection')}
37	      data-test-id={dataTestID}
38	      isExpanded={isExpanded}
39	      isIndented={isIndented}
40	      onToggle={(_event, expanded: boolean) => handleToggle(expanded)}
41	      toggleContent={toggleContent}
42	      toggleText={toggleText}
43	    >
44	      {children}
45	    </ExpandableSection>
46	  );
47	};
48	
49	export default ExpandSection;

